e=&gt;end: 结束节点
op1=&gt;operation: xx
op2=&gt;operation: xx
cond=&gt;condition: i被2整除
sub=&gt;subroutine: xx
out1=&gt;inputoutput: 输出i是奇数
out2=&gt;inputoutput: 输出i是偶数
st-&gt;in-&gt;cond
cond(yes,right)-&gt;out2-&gt;e
cond(no)-&gt;out1-&gt;e&lt;/textarea&gt;&lt;textarea id=&#34;flowchart-1-options&#34; style=&#34;display: none&#34;&gt;{&#34;scale&#34;:1,&#34;line-width&#34;:2,&#34;line-length&#34;:50,&#34;text-margin&#34;:10,&#34;font-size&#34;:12}&lt;/textarea&gt;&lt;script&gt;  var code = document.getElementById(&#34;flowchart-1-code&#34;).value;  var options = JSON.parse(decodeURIComponent(document.getElementById(&#34;flowchart-1-options&#34;).value));  var diagram = flowchart.parse(code);  diagram.drawSVG(&#34;flowchart-1&#34;, options);&lt;/script&gt;&lt;/p&gt;

 &lt;p&gt;&lt;img src=&#34;\pic\2020\12\最小二乘法的算术推导.png&#34; alt=&#34;最小二乘法的算术推导&#34;&gt;&lt;/p&gt;
&lt;p&gt;$\hat y=a+bx$&lt;/p&gt;
&lt;p&gt;$\begin{aligned} Q&amp;amp;=\displaystyle \sum^n_{i=1}{(y_i-\hat y)^2}\\\&lt;br&gt;&amp;amp;={(y_1-\hat y_1)^2}+{(y_2-\hat y_2)^2}+ \cdots +{(y_n-\hat y_n)^2} \end{aligned}$&lt;/p&gt;
&lt;p&gt;其中$\hat y$为回归方程，求$Q$最小时回归方程的系数a，b取值。&lt;/p&gt;
&lt;h2 id=&#34;具体推导如下：&#34;&gt;&lt;a href=&#34;#具体推导如下：&#34; class=&#34;headerlink&#34; title=&#34;具体推导如下：&#34;&gt;&lt;/a&gt;具体推导如下：&lt;/h2&gt;&lt;h2 id=&#34;一、预备公式&#34;&gt;&lt;a href=&#34;#一、预备公式&#34; class=&#34;headerlink&#34; title=&#34;一、预备公式&#34;&gt;&lt;/a&gt;&lt;strong&gt;一、预备公式&lt;/strong&gt;&lt;/h2&gt;&lt;h3 id=&#34;1-gt&#34;&gt;&lt;a href=&#34;#1-gt&#34; class=&#34;headerlink&#34; title=&#34;1&amp;gt;&#34;&gt;&lt;/a&gt;1&amp;gt;&lt;/h3&gt;&lt;p&gt;$\displaystyle \sum^n_{i=1}{(x_i-{\bar x})^2}=\displaystyle \sum^n_{i=1}{x_i^2-n{\bar x}^2}$,&lt;/p&gt;
&lt;p&gt;其中:$\bar x=\frac {x_1+x_2+\cdots +x_n}{n}$&lt;/p&gt;
&lt;h5 id=&#34;推导&#34;&gt;&lt;a href=&#34;#推导&#34; class=&#34;headerlink&#34; title=&#34;推导:&#34;&gt;&lt;/a&gt;&lt;strong&gt;推导:&lt;/strong&gt;&lt;/h5&gt;&lt;p&gt;$\begin{aligned} 左边&amp;amp;={(x_1-\bar x_1)^2}+{(x_2-\bar x_2)^2}+ \cdots +{(x_n-\bar x_n)^2}\\\&lt;br&gt;&amp;amp;=x_1^2+x_2^2+ \cdots +x_n^2-2\bar x·(x_1+x_2+ \cdots +x_n)+n\bar x^2\\\&lt;br&gt;&amp;amp;=\displaystyle \sum^n_{i=1}{x_i^2}-2\bar x·n·\bar x + n·\bar x^2\\\&lt;br&gt;&amp;amp;=\displaystyle\sum^n_{i=1}{x_i^2-n\bar x^2}=右边 \end{aligned}$&lt;/p&gt;
&lt;h3 id=&#34;2-gt&#34;&gt;&lt;a href=&#34;#2-gt&#34; class=&#34;headerlink&#34; title=&#34;2&amp;gt;&#34;&gt;&lt;/a&gt;2&amp;gt;&lt;/h3&gt;&lt;p&gt;$\displaystyle\sum^n_{i=1}{(x_i-\bar x)}{(y_i-\bar y)}=\displaystyle \sum^n_{i=1}{x_i}{y_i}-n\bar x\bar y$，&lt;/p&gt;
&lt;p&gt;其中:$\bar x=\frac {x_1+x_2+\cdots+x_n}{n},\bar y=\frac{y_1+y_2+\cdots + y_n}{n}$&lt;/p&gt;
&lt;h5 id=&#34;推导：&#34;&gt;&lt;a href=&#34;#推导：&#34; class=&#34;headerlink&#34; title=&#34;推导：&#34;&gt;&lt;/a&gt;&lt;strong&gt;推导：&lt;/strong&gt;&lt;/h5&gt;&lt;p&gt;$\begin{aligned} 左边&amp;amp;={(x_1-\bar x_1)}{(y_1-\bar y_1)}+{(x_2-\bar x_2)}{(y_2-\bar y_2)}+ \cdots +{(x_n-\bar x_n)}{(y_n-\bar y_n)}\\\&lt;br&gt;&amp;amp;=(x_1y_1+x_2y_2+\cdots+x_n·y_n)+n\bar x·\bar y-(y_1+y_2+\cdots+y_n)·\bar x-(x_1+x_2+\cdots+x_n)·\bar y\\\&lt;br&gt;&amp;amp;=\displaystyle\sum^ n_{i=1}{x_i}{y_i}+n\bar x·\bar y-n\bar y·\bar x-n\bar x\bar y\\\&lt;br&gt;&amp;amp;=\displaystyle\sum^n_{i=1}{x_i}{y_i}-n\bar x\bar y=右边 \end{aligned}$&lt;/p&gt;
&lt;h2 id=&#34;二、推导过程&#34;&gt;&lt;a href=&#34;#二、推导过程&#34; class=&#34;headerlink&#34; title=&#34;二、推导过程&#34;&gt;&lt;/a&gt;&lt;strong&gt;二、推导过程&lt;/strong&gt;&lt;/h2&gt;&lt;p&gt;$\begin{aligned} Q &amp;amp;=\displaystyle \sum^n_{i=1}{(y_i-\hat y)^2}\\\&lt;br&gt;&amp;amp;=\displaystyle \sum^n_{i=1}{[y_i-(a+bx_i)]}^2\\\&lt;br&gt;&amp;amp;=(y_1^2+y_2^2+ \cdots +y_n^2)+na^2+b^2(x_1^2 + x_2^2 + \cdots +x_n^2)+2a·b·(x_1+x_2+\cdots+x_n)-2a·(y_1+y_2+\cdots +y_n)-2b(x_1·y_1+x_2·y_2+\cdots +x_n·y_n)\\\&lt;br&gt;&amp;amp;=\displaystyle \sum^n_{i=1}y_i^2+na^2+b^2·\displaystyle \sum^n_{i=1}x_i^2+2ab·n·\bar x-2a·n·\bar y-2b·\displaystyle \sum^n_{i=1}x_iy_i\\\&lt;br&gt;&amp;amp;=\displaystyle \sum^n_{i=1}y_i^2-2b\displaystyle \sum^n_{i=1}x_iy_i+b^2·\displaystyle \sum^n_{i=1}x_i^2+na^2-n·2a·(\bar y-b\bar x)\\\&lt;br&gt;&amp;amp;=\displaystyle \sum^n_{i=1}y_i^2-2b\displaystyle \sum^n_{i=1}x_iy_i+b^2·\displaystyle \sum^n_{i=1}x_i^2+n[a-(\bar y-b\bar x)]^2-n[(\bar y-b\bar x)]^2\\\&lt;br&gt;&amp;amp;=n[(\bar y-b\bar x)]^2-n\bar y^2+2n·b·\bar x·\bar y-n·b^2·\bar x^2+b^2·\displaystyle \sum^n_{i=1}x_i^2-2b·\displaystyle \sum^n_{i=1}x_iy_i+\displaystyle \sum^n_{i=1}y_i^2\\\&lt;br&gt;&amp;amp;=n[(\bar y-b\bar x)]^2+b^2(\displaystyle \sum^n_{i=1}x_i^2-n·\bar x^2)+\displaystyle \sum^n_{i=1}y_i^2-n·\bar y^2-2b·(\displaystyle \sum^n_{i=1}x_iy_i-n·\bar x·\bar y)\\\&lt;br&gt;&amp;amp;=n[a-(\bar y-b\bar x)]^2+b^2{\displaystyle \sum^n_{i=1}(x_i-\bar x)^2}-2b·\displaystyle \sum^n_{i=1}{(x_i-\bar x)(y_i-\bar y)}+\displaystyle \sum^n_{i=1}y_i^2-n·\bar y^2\\\&lt;br&gt;&amp;amp;=n[a-(\bar y-b\bar x)]^2+{\displaystyle \sum^n_{i=1}(x_i-\bar x)^2}·\left [b^2-2b·\frac {\displaystyle \sum^n_{i=1}(x_i-\bar x)(y_i-\bar y)}{\displaystyle \sum^n_{i=1}{(x_i-\bar x)^2}}\right ] +\displaystyle \sum^n_{i=1}y_i-n·\bar y^2\\\&lt;br&gt;&amp;amp;=n[a-(\bar y-b\bar x)]^2+{\displaystyle \sum^n_{i=1}(x_i-\bar x)^2}·\left [b-\frac {\displaystyle \sum^n_{i=1}(x_i-\bar x)(y_i-\bar y)}{\displaystyle \sum^n_{i=1}{(x_i-\bar x)^2}}\right ]^2-\frac {\left [{\displaystyle \sum^n_{i=1}}(x_i-{\bar x})(y_i-\bar y)\right ]^2}{\displaystyle \sum^n_{i=1}{(x_i-\bar x)^2}}+ \displaystyle \sum^n_{i=1}y_i-n·\bar y^2 \end{aligned}$&lt;br&gt;因为：&lt;/p&gt;
&lt;script type=&#34;math/tex; mode=display&#34;&gt;\displaystyle \sum^n_{i=1}(x_i-\bar x)^2&lt;/script&gt;&lt;p&gt;和&lt;/p&gt;
&lt;script type=&#34;math/tex; mode=display&#34;&gt;\frac {[\displaystyle \sum^n_{i=1}(x_i-\bar x)(y_i-\bar y)]^2}{\displaystyle \sum^n_{i=1}(x_i-\bar x)^2}&lt;/script&gt;&lt;p&gt;及&lt;/p&gt;
&lt;script type=&#34;math/tex; mode=display&#34;&gt;\displaystyle \sum^n_{i=1}y_i-n·\bar y^2&lt;/script&gt;&lt;p&gt;为常数。&lt;/p&gt;
&lt;p&gt;所以:&lt;/p&gt;
&lt;script type=&#34;math/tex; mode=display&#34;&gt;Q_{min}=
\begin{cases}
a-(\bar y-b\bar x)=0\\\
b-\frac {\displaystyle \sum^n_{i=1}(x_i-\bar x)(y_i-\bar y)}{\displaystyle \sum^n_{i=1}(x_i-\bar x)^2}=0
\end{cases}
\Longrightarrow \begin{cases} a=\bar y-b\bar x\\\
b=\frac {\displaystyle \sum^n_{i=1}(x_iy_i-n·\bar x\bar y)}{\displaystyle \sum^n_{i=1}x_i^2-n·\bar x^2}
\end{cases}&lt;/script&gt;

 &lt;p&gt;代码如下：&lt;/p&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs python&#34;&gt;&lt;span class=&#34;hljs-comment&#34;&gt;#!/usr/bin/env python&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# -*- coding: utf-8 -*-&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# @Date    : 2020-12-19 15:02:56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# @Author  : KY (xxxxxx@g.com)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# @Link    : http://example.org&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# @Version : $Id$&lt;/span&gt;&lt;br&gt;&lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; os&lt;br&gt;&lt;br&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;rename&lt;/span&gt;():&lt;/span&gt;&lt;br&gt;    name = &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;p&amp;quot;&lt;/span&gt;;&lt;br&gt;    count = &lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;;&lt;br&gt;    path = &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;F:\Pictures\Assets&amp;quot;&lt;/span&gt; &lt;span class=&#34;hljs-comment&#34;&gt;#文件所在路径&lt;/span&gt;&lt;br&gt;&lt;br&gt;    filelist = os.listdir(path) &lt;span class=&#34;hljs-comment&#34;&gt;#该文件夹下所有的文件（包括文件夹）&lt;/span&gt;&lt;br&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;for&lt;/span&gt; files &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; filelist: &lt;span class=&#34;hljs-comment&#34;&gt;#遍历所有文件&lt;/span&gt;&lt;br&gt;        Olddir = os.path.join(path,files) &lt;span class=&#34;hljs-comment&#34;&gt;#原来的文件路径&lt;/span&gt;&lt;br&gt;        &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; os.path.isdir(Olddir): &lt;span class=&#34;hljs-comment&#34;&gt;#如果是文件夹就跳过&lt;/span&gt;&lt;br&gt;            &lt;span class=&#34;hljs-keyword&#34;&gt;continue&lt;/span&gt;&lt;br&gt;        filename = os.path.splitext(files)[&lt;span class=&#34;hljs-number&#34;&gt;0&lt;/span&gt;] &lt;span class=&#34;hljs-comment&#34;&gt;#文件名&lt;/span&gt;&lt;br&gt;        filetype = os.path.splitext(files)[&lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;] &lt;span class=&#34;hljs-comment&#34;&gt;#扩展名&lt;/span&gt;&lt;br&gt;        Newdir = os.path.join(path,&lt;span class=&#34;hljs-built_in&#34;&gt;str&lt;/span&gt;(name)+&lt;span class=&#34;hljs-built_in&#34;&gt;str&lt;/span&gt;(count)+filetype) &lt;span class=&#34;hljs-comment&#34;&gt;#新文件路径&lt;/span&gt;&lt;br&gt;        os.rename(Olddir,Newdir) &lt;span class=&#34;hljs-comment&#34;&gt;#重新命名&lt;/span&gt;&lt;br&gt;        count += &lt;span class=&#34;hljs-number&#34;&gt;1&lt;/span&gt;&lt;br&gt;rename()&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;最终效果如图： &lt;img src=&#34;/pic/2020/12/Python批量重命名.jpg&#34; alt=&#34;重命名&#34;&gt;&lt;/p&gt;

 &lt;p&gt;asp查询页面&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs asp&#34;&gt;response.expires=-1&lt;br&gt;user = trim(request.querystring(&amp;quot;name&amp;quot;))&lt;br&gt;if user = &amp;quot;&amp;quot; then&lt;br&gt;    response.write escape(&amp;quot;&amp;lt;font style=&amp;quot;&amp;quot;color:red&amp;quot;&amp;quot;&amp;gt;姓名或学员ID不能为空格！&amp;lt;/font&amp;gt;&amp;quot;)&lt;br&gt;    response.End()&lt;br&gt;end if&lt;br&gt;sql = &amp;quot;select * from students where usrname =&amp;#x27;&amp;quot;&amp;amp;user&amp;amp;&amp;quot;&amp;#x27; or usr_ID=&amp;#x27;&amp;quot;&amp;amp;user&amp;amp;&amp;quot;&amp;#x27;&amp;quot;&lt;br&gt;&amp;#x27;sql = sql &amp;amp;&amp;quot;&amp;#x27;&amp;quot;&amp;amp; request.querystring(&amp;quot;name&amp;quot;) &amp;amp;&amp;quot;&amp;#x27;&amp;quot;&lt;br&gt;&amp;#x27;使用sql对conn进行查询，后面的参数代表我要完全操作这个数据库&lt;br&gt;Set rs = Server.CreateObject( &amp;quot;ADODB.Recordset&amp;quot; )&lt;br&gt;rs.open sql,conn,1,1&lt;br&gt;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;js处理页面&lt;/p&gt;
&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs javascript&#34;&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;createAjax&lt;/span&gt;(&lt;span class=&#34;hljs-params&#34;&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123;&lt;span class=&#34;hljs-comment&#34;&gt;//该函数将返回XMLHTTP对象实例&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;var&lt;/span&gt; _xmlhttp; &lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;try&lt;/span&gt; &amp;#123; &lt;br&gt;    _xmlhttp=&lt;span class=&#34;hljs-keyword&#34;&gt;new&lt;/span&gt; ActiveXObject(&lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;Microsoft.XMLHTTP&amp;quot;&lt;/span&gt;); &lt;br&gt;    &amp;#125; &lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;catch&lt;/span&gt; (e) &amp;#123; &lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;try&lt;/span&gt; &amp;#123; &lt;br&gt;    _xmlhttp=&lt;span class=&#34;hljs-keyword&#34;&gt;new&lt;/span&gt; XMLHttpRequest(); &lt;br&gt; &amp;#125; &lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;catch&lt;/span&gt; (e) &amp;#123; &lt;br&gt;    _xmlhttp=&lt;span class=&#34;hljs-literal&#34;&gt;false&lt;/span&gt;; &lt;br&gt;    &amp;#125; &lt;br&gt;&amp;#125; &lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;return&lt;/span&gt; _xmlhttp; &lt;br&gt;&amp;#125;&lt;br&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;checkname&lt;/span&gt;(&lt;span class=&#34;hljs-params&#34;&gt;name&lt;/span&gt;) &lt;/span&gt;&amp;#123; &lt;span class=&#34;hljs-comment&#34;&gt;//该函数用来获取数据 用户名//alert(idname)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;var&lt;/span&gt; xmlhttp1=createAjax();&lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (xmlhttp1) &amp;#123;&lt;br&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;var&lt;/span&gt; span=&lt;span class=&#34;hljs-built_in&#34;&gt;document&lt;/span&gt;.getElementById(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;check&amp;#x27;&lt;/span&gt;); &lt;span class=&#34;hljs-comment&#34;&gt;// 获取显示节点  &lt;/span&gt;&lt;br&gt;    xmlhttp1.open(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;get&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;checkname.asp?name=&amp;#x27;&lt;/span&gt;+name+&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;&amp;amp;n=&amp;#x27;&lt;/span&gt;+&lt;span class=&#34;hljs-built_in&#34;&gt;Math&lt;/span&gt;.random(),&lt;span class=&#34;hljs-literal&#34;&gt;true&lt;/span&gt;);   &lt;br&gt;    xmlhttp1.onreadystatechange=&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;function&lt;/span&gt;(&lt;span class=&#34;hljs-params&#34;&gt;&lt;/span&gt;) &lt;/span&gt;&amp;#123; &lt;br&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; (xmlhttp1.readyState==&lt;span class=&#34;hljs-number&#34;&gt;4&lt;/span&gt; &amp;amp;&amp;amp; xmlhttp1.status==&lt;span class=&#34;hljs-number&#34;&gt;200&lt;/span&gt;)&amp;#123;&lt;br&gt;        span.innerHTML=&lt;span class=&#34;hljs-built_in&#34;&gt;unescape&lt;/span&gt;(xmlhttp1.responseText);&lt;br&gt;          &amp;#125;    &lt;br&gt;    &lt;span class=&#34;hljs-keyword&#34;&gt;else&lt;/span&gt; &amp;#123;&lt;br&gt;        span.innerHTML=&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;&amp;lt;span style=&amp;quot;color:red&amp;quot;&amp;gt;xmlhttp对象正在初始化......&amp;lt;/span&amp;gt;&amp;#x27;&lt;/span&gt;;    &lt;br&gt;    &amp;#125;&lt;br&gt;&amp;#125;  &lt;br&gt;    xmlhttp1.send(&lt;span class=&#34;hljs-literal&#34;&gt;null&lt;/span&gt;);&lt;br&gt;  &amp;#125;&lt;br&gt;  &amp;#125;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2 id=&#34;一、利用mysqldump备份与恢复命令：&#34;&gt;&lt;a href=&#34;#一、利用mysqldump备份与恢复命令：&#34; class=&#34;headerlink&#34; title=&#34;一、利用mysqldump备份与恢复命令：&#34;&gt;&lt;/a&gt;一、利用&lt;code&gt;mysqldump&lt;/code&gt;备份与恢复命令：&lt;/h2&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs mysql&#34;&gt;$ sudo mysqldump -uroot -p wpDB &amp;gt; /home/yk/mysql-wpDB.dump  //备份数据库名及保存路径&lt;br&gt;&lt;br&gt;$ sudo mysql -uroot  //进入数据库&lt;br&gt;MariaDB [(none)]&amp;gt; create database wpDBtest; //创建测试恢复数据库,单库备份需先创建该数据库&lt;br&gt;$ mysql -uroot -pyinkai wpDBtest &amp;lt; /home/yk/mysql-wpDB.dump;  //恢复数据库&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;注意：上诉备份方案存在一定的弊端如：用户正在执行数据操作时，数据则会丢失等情况。 &lt;/p&gt;
&lt;p&gt;解决方案：  &lt;/p&gt;
&lt;h4 id=&#34;1》在备份数据库表加上锁，保证数据的完整性。&#34;&gt;&lt;a href=&#34;#1》在备份数据库表加上锁，保证数据的完整性。&#34; class=&#34;headerlink&#34; title=&#34;1》在备份数据库表加上锁，保证数据的完整性。&#34;&gt;&lt;/a&gt;1》在备份数据库表加上锁，保证数据的完整性。&lt;/h4&gt;&lt;p&gt;&lt;code&gt;--lock-all-tables&lt;/code&gt;:请求锁定所有表&lt;br&gt;实例：&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs mysql&#34;&gt;$ mysqldump --databases wpDBtest --lock-all-tables &amp;gt;/home/yk/wpDBtest .sql &lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;--single-transaction&lt;/code&gt;:单事务，能够对&lt;code&gt;innodb&lt;/code&gt;存储引擎做热备 &lt;/p&gt;
&lt;p&gt;&lt;code&gt;--events&lt;/code&gt;:备份事件调度器代码&lt;/p&gt;
&lt;p&gt;&lt;code&gt;--routines&lt;/code&gt;:备份存储过程和存储函数&lt;/p&gt;
&lt;p&gt;&lt;code&gt;--triggers&lt;/code&gt;:备份触发器 &lt;/p&gt;
&lt;p&gt;备份时请求锁之后滚动日志：&lt;code&gt;--flush-logs&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;复制时同步位置标记：&lt;code&gt;--master-data=[0|1|2]&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;注意：恢复时需关闭二进制文件，恢复成功后则开启&lt;/p&gt;
&lt;p&gt;关闭二进制日志：&lt;code&gt;set session sql_log_bin=0&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;开启二进制日志：&lt;code&gt;set session sql_log_bin=1&lt;/code&gt;&lt;/p&gt;
&lt;h4 id=&#34;2》锁表备份步骤：&#34;&gt;&lt;a href=&#34;#2》锁表备份步骤：&#34; class=&#34;headerlink&#34; title=&#34;2》锁表备份步骤：&#34;&gt;&lt;/a&gt;2》锁表备份步骤：&lt;/h4&gt;&lt;h5 id=&#34;1-锁表并且给只读权限&#34;&gt;&lt;a href=&#34;#1-锁表并且给只读权限&#34; class=&#34;headerlink&#34; title=&#34;1)锁表并且给只读权限&#34;&gt;&lt;/a&gt;1)锁表并且给只读权限&lt;/h5&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs mysql&#34;&gt;MariaDB [(none)]&amp;gt;flush tables with read lock;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;2-滚动日志&#34;&gt;&lt;a href=&#34;#2-滚动日志&#34; class=&#34;headerlink&#34; title=&#34;2)滚动日志&#34;&gt;&lt;/a&gt;2)滚动日志&lt;/h5&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs mysql&#34;&gt;MariaDB [(none)]&amp;gt;flush logs;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;3-查看二进制日志信息&#34;&gt;&lt;a href=&#34;#3-查看二进制日志信息&#34; class=&#34;headerlink&#34; title=&#34;3)查看二进制日志信息&#34;&gt;&lt;/a&gt;3)查看二进制日志信息&lt;/h5&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs mysql&#34;&gt;MariaDB [(none)]&amp;gt;show master status; &lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;4-使用mysqldump进行数据备份&#34;&gt;&lt;a href=&#34;#4-使用mysqldump进行数据备份&#34; class=&#34;headerlink&#34; title=&#34;4)使用mysqldump进行数据备份&#34;&gt;&lt;/a&gt;4)使用&lt;code&gt;mysqldump&lt;/code&gt;进行数据备份&lt;/h5&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs mysql&#34;&gt;$ mysqldump --databases wpDBtest &amp;gt;/tmp/wpDBtest.sql&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;5-备份完成之后则需解锁&#34;&gt;&lt;a href=&#34;#5-备份完成之后则需解锁&#34; class=&#34;headerlink&#34; title=&#34;5)备份完成之后则需解锁&#34;&gt;&lt;/a&gt;5)备份完成之后则需解锁&lt;/h5&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs mysql&#34;&gt;MariaDB [(none)]&amp;gt;unlock tables; &lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;命令行备份实例如下：&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs mysql&#34;&gt;mysqldump -p --databases wpDBtest --lock-all-tables --flush-logs &amp;gt;/home/yk/wpDBtest2.sql &lt;br&gt;mysqldump -p --databases wpDBtest --single-trasaction --flush-logs &amp;gt;/home/yk/wpDBtest3.sql &lt;br&gt;mysqldump -p --databases wpDBtest --lock-all-tables --flush-logs --master-data=2 &amp;gt;/home/yk/wpDBtest4.sql&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;2》查看恢复的数据&#34;&gt;&lt;a href=&#34;#2》查看恢复的数据&#34; class=&#34;headerlink&#34; title=&#34;2》查看恢复的数据&#34;&gt;&lt;/a&gt;2》查看恢复的数据&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs mysql&#34;&gt;$ sudo mysql -uroot  //进入数据库 &lt;br&gt;$ use wpDBtest;   /选择查看数据库&lt;br&gt;MariaDB [wpDBtest]&amp;gt; select * from wp_options where option_name in(&amp;quot;siteurl&amp;quot;,&amp;quot;home&amp;quot;); //查看恢复信息&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;二、用二进制日志恢复命令：&#34;&gt;&lt;a href=&#34;#二、用二进制日志恢复命令：&#34; class=&#34;headerlink&#34; title=&#34;二、用二进制日志恢复命令：&#34;&gt;&lt;/a&gt;二、用二进制日志恢复命令：&lt;/h2&gt;&lt;h3 id=&#34;1》开启binlog&#34;&gt;&lt;a href=&#34;#1》开启binlog&#34; class=&#34;headerlink&#34; title=&#34;1》开启binlog&#34;&gt;&lt;/a&gt;1》开启&lt;code&gt;binlog&lt;/code&gt;&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs linux&#34;&gt;$ sudo vim /etc/alternatives/my.cnf  //添加如下内容，开启binlog&lt;br&gt;[mysqld]&lt;br&gt;log_bin=mysql-bin&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2》-查看log-bin是否开启&#34;&gt;&lt;a href=&#34;#2》-查看log-bin是否开启&#34; class=&#34;headerlink&#34; title=&#34;2》//查看log_bin是否开启&#34;&gt;&lt;/a&gt;2》//查看&lt;code&gt;log_bin&lt;/code&gt;是否开启&lt;/h3&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs mysql&#34;&gt;MariaDB [(none)]&amp;gt;  show variables like &amp;#x27;log_bin&amp;#x27;;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;//查看二进制&lt;code&gt;log&lt;/code&gt;，&lt;code&gt;--no-defaults&lt;/code&gt;避免出现字符问题错误&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs linux&#34;&gt;$ sudo mysqlbinlog --no-defaults /var/lib/mysql/mysql-bin.000001;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h3 id=&#34;3》测试过程&#34;&gt;&lt;a href=&#34;#3》测试过程&#34; class=&#34;headerlink&#34; title=&#34;3》测试过程&#34;&gt;&lt;/a&gt;3》测试过程&lt;/h3&gt;&lt;h4 id=&#34;1、创建测试数据库并新增表和记录&#34;&gt;&lt;a href=&#34;#1、创建测试数据库并新增表和记录&#34; class=&#34;headerlink&#34; title=&#34;1、创建测试数据库并新增表和记录&#34;&gt;&lt;/a&gt;1、创建测试数据库并新增表和记录&lt;/h4&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs mysql&#34;&gt;MariaDB [wpDBtest]&amp;gt; create database testDB;&lt;br&gt;MariaDB [testDB]&amp;gt; create table testtable (id int null, name varchar(255) null);&lt;br&gt;MariaDB [(none)]&amp;gt; source /home/yk/wpDBtest-re.sql&lt;br&gt;MariaDB [testDB]&amp;gt; insert into testtable values(1,&amp;quot;xiaoming&amp;quot;);&lt;br&gt;MariaDB [testDB]&amp;gt; insert into testtable values(2,&amp;quot;wang&amp;quot;);&lt;br&gt;MariaDB [testDB]&amp;gt; insert into testtable values(3,&amp;quot;王&amp;quot;);&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;2、删除一条测试数据&#34;&gt;&lt;a href=&#34;#2、删除一条测试数据&#34; class=&#34;headerlink&#34; title=&#34;2、删除一条测试数据&#34;&gt;&lt;/a&gt;2、删除一条测试数据&lt;/h4&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs mysql&#34;&gt;MariaDB [testDB]&amp;gt; delete from testtable where id =2;&lt;br&gt;##MariaDB [testDB]&amp;gt; delete from testtable;&lt;br&gt;##Query OK, 5 rows affected (0.027 sec)&lt;br&gt;MariaDB [testDB]&amp;gt; select * from testtable; //显示如下：&lt;br&gt;+------+----------+&lt;br&gt;| id   | name     |&lt;br&gt;+------+----------+&lt;br&gt;|    1 | xiaoming |&lt;br&gt;|    3 | 王       |&lt;br&gt;+------+----------+&lt;br&gt;2 rows in set (0.001 sec)&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;3、导出二进制log为sql-database-testDB-指定导出数据库testDB的数据&#34;&gt;&lt;a href=&#34;#3、导出二进制log为sql-database-testDB-指定导出数据库testDB的数据&#34; class=&#34;headerlink&#34; title=&#34;3、导出二进制log为sql,--database=testDB 指定导出数据库testDB的数据&#34;&gt;&lt;/a&gt;3、导出二进制&lt;code&gt;log&lt;/code&gt;为&lt;code&gt;sql&lt;/code&gt;,&lt;code&gt;--database=testDB&lt;/code&gt; 指定导出数据库&lt;code&gt;testDB&lt;/code&gt;的数据&lt;/h4&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs linux&#34;&gt;$ sudo  mysqlbinlog --no-defaults --database=testDB /var/lib/mysql/mysql-bin.000001&amp;gt;/home/yk/testDB.sql;&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;4、进入-home-yk-文件夹，复制原数据并另存testDB-re-sql&#34;&gt;&lt;a href=&#34;#4、进入-home-yk-文件夹，复制原数据并另存testDB-re-sql&#34; class=&#34;headerlink&#34; title=&#34;4、进入/home/yk/文件夹，复制原数据并另存testDB-re.sql&#34;&gt;&lt;/a&gt;4、进入&lt;code&gt;/home/yk/&lt;/code&gt;文件夹，复制原数据并另存&lt;code&gt;testDB-re.sql&lt;/code&gt;&lt;/h4&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs linux&#34;&gt;$ cp testDB.sql testDB-re.sql&lt;br&gt;$ sudo vim testDB-re.sql  //打开sql文件，删除其中“delete from testtable where id =2”语句&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;5、进入mariadb，恢复数据&#34;&gt;&lt;a href=&#34;#5、进入mariadb，恢复数据&#34; class=&#34;headerlink&#34; title=&#34;5、进入mariadb，恢复数据&#34;&gt;&lt;/a&gt;5、进入&lt;code&gt;mariadb&lt;/code&gt;，恢复数据&lt;/h4&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs msyql&#34;&gt;MariaDB [testDB]&amp;gt; source /home/yk/testDB-re.sql&lt;br&gt;MariaDB [testDB]&amp;gt; select * from testtable;&lt;br&gt;+------+----------+&lt;br&gt;| id   | name     |&lt;br&gt;+------+----------+&lt;br&gt;|    1 | xiaoming |&lt;br&gt;|    3 | 王       |&lt;br&gt;|    1 | xiaoming |&lt;br&gt;|    2 | wang     |&lt;br&gt;|    3 | 王       |&lt;br&gt;+------+----------+&lt;br&gt;5 rows in set (0.001 sec)&lt;br&gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;参考资料：&lt;br&gt;&lt;a href=&#34;https://blog.51cto.com/purify/1860516&#34;&gt;mariadb二进制日志和备份恢复&lt;/a&gt;&lt;/p&gt;

&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter hljs&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;div class=&#34;hljs code-wrapper&#34;&gt;&lt;pre&gt;&lt;code class=&#34;hljs python&#34;&gt;&lt;span class=&#34;hljs-comment&#34;&gt;#!/usr/bin/env python&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# -*- coding: utf-8 -*-&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# @Date : 2019-03-18 13:02:32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# @Author : KK (xxxxx@xxxxx.com)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# @Link : http://default.com&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# @Version : $Id$&lt;/span&gt;&lt;br&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;# -*- coding: utf-8 -*-&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; urllib.request &lt;br&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;from&lt;/span&gt; bs4 &lt;span class=&#34;hljs-keyword&#34;&gt;import&lt;/span&gt; BeautifulSoup&lt;br&gt;&lt;br&gt;&lt;span class=&#34;hljs-comment&#34;&gt;#get book&amp;#x27;s chapter&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;hljs-function&#34;&gt;&lt;span class=&#34;hljs-keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;hljs-title&#34;&gt;get_chapter&lt;/span&gt;(&lt;span class=&#34;hljs-params&#34;&gt;url&lt;/span&gt;):&lt;/span&gt;&lt;br&gt; html = urllib.request.urlopen(url) &lt;br&gt; content = html.read().decode(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;utf8&amp;#x27;&lt;/span&gt;)&lt;br&gt; html.close()&lt;br&gt; soup = BeautifulSoup(content, &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;lxml&amp;quot;&lt;/span&gt;)&lt;br&gt; title = soup.find(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;h1&amp;#x27;&lt;/span&gt;).text &lt;span class=&#34;hljs-comment&#34;&gt;#chapter title&lt;/span&gt;&lt;br&gt; text = soup.find(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;div&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;hljs-built_in&#34;&gt;id&lt;/span&gt;=&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;htmlContent&amp;#x27;&lt;/span&gt;) &lt;span class=&#34;hljs-comment&#34;&gt;#chapter content&lt;/span&gt;&lt;br&gt; &lt;span class=&#34;hljs-comment&#34;&gt;#processing the content to get nice style&lt;/span&gt;&lt;br&gt; content = text.get_text(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;
&amp;#x27;&lt;/span&gt;,&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;br/&amp;#x27;&lt;/span&gt;).replace(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;
&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;
 &amp;#x27;&lt;/span&gt;)&lt;br&gt; content = content.replace(&lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27; &amp;#x27;&lt;/span&gt;, &lt;span class=&#34;hljs-string&#34;&gt;&amp;#x27;
